const region = ($input.first() && $input.first().json && $input.first().json.region) || 'manual';
return [
  { json: { url: 'https://techcrunch.com', source: 'TechCrunch', region } },
  { json: { url: 'https://venturebeat.com', source: 'VentureBeat', region } },
  { json: { url: 'https://www.technologyreview.com', source: 'MIT Tech Review', region } }
];

const data = $input.first().json;
const source = $('Source list').first().json.source;
const links = (data.data && data.data.links) ? data.data.links : [];
const MAX_ARTICLES = 25;

const hash = (s) => {
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16);
};

return links.slice(0, MAX_ARTICLES).map(url => ({
  json: { url, source_name: source, fingerprint: hash(url) }
}));

const MAX_ARTICLES = 10;
const MIN_ARTICLES = 7;
const items = $input.all();

const systemPrompt = [
  `You are an autonomous AI news editor. Your task is to select the BEST articles for a daily briefing targeting busy tech professionals and business leaders.`,
  ``,
  `CRITICAL RULES — YOU MUST FOLLOW THESE EXACTLY:`,
  `1. You MUST select a MINIMUM of ${MIN_ARTICLES} articles and a MAXIMUM of ${MAX_ARTICLES} articles.`,
  `2. Selecting fewer than ${MIN_ARTICLES} or more than ${MAX_ARTICLES} is a VIOLATION. Do not do it.`,
  `3. Rank by: business impact, novelty, and relevance to tech industry.`,
  `4. Exclude: paywalled articles, listicles, press releases, and opinion pieces with no news value.`,
  `5. PREFER articles where is_repeat is false (fresh in this region). Only include articles where is_repeat is true if has_update is true — those are genuine updates worth re-airing. NEVER select an article where is_repeat is true and has_update is false; those are stale repeats.`,
  `6. Output ONLY valid JSON with exactly two keys:`,
  `   - "selected_fingerprints": an array of EXACTLY ${MIN_ARTICLES}–${MAX_ARTICLES} fingerprint strings`,
  `   - "rationale": one short sentence explaining the selection`
].join('\n');

const userContent = [
  `Here are ${items.length} articles to evaluate. Select between ${MIN_ARTICLES} and ${MAX_ARTICLES} of them.`,
  ``,
  JSON.stringify(items.map(i => ({
    fingerprint: i.json.fingerprint,
    headline: i.json.headline,
    source: i.json.source_name,
    is_repeat: !!i.json.is_repeat,
    has_update: !!i.json.has_update,
    first_aired_at: i.json.first_aired_at || null
  }))),
  ``,
  `REMINDER: Your response MUST contain between ${MIN_ARTICLES} and ${MAX_ARTICLES} fingerprints in selected_fingerprints. Not more, not fewer.`
].join('\n');

const payload = {
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userContent }
  ],
  temperature: 0,
  response_format: { type: 'json_object' }
};
return [{ json: { llm_payload: payload, max_articles: MAX_ARTICLES, min_articles: MIN_ARTICLES } }];

const input = $input.first().json;
let rawContent = input.choices[0].message.content || '';
rawContent = rawContent.replace(/^```(?:json)?\n/i, '').replace(/\n```$/i, '').trim();

let decision;
try {
  decision = JSON.parse(rawContent);
} catch (e) {
  throw new Error(`Failed to parse LLM response as JSON. Raw content: ${JSON.stringify(rawContent)}`);
}
let fps = decision.selected_fingerprints;
if (!Array.isArray(fps)) fps = [];

const maxArticles = $('Build Editor Payload').first().json.max_articles || 10;
const orderedFps = fps.slice(0, maxArticles);
const rankByFp = new Map(orderedFps.map((fp, idx) => [fp, idx + 1]));

// Preserve the editor's selection order so rank tracks LLM ranking.
const allItems = $('Postgres: Read raw articles').all();
const byFp = new Map(allItems.map(i => [i.json.fingerprint, i.json]));
const selected = orderedFps
  .map(fp => byFp.get(fp))
  .filter(Boolean);

const targetLength = Math.max(30, Math.floor(350 / Math.max(1, selected.length)));
return selected.map(rawItem => ({
  json: {
    ...rawItem,
    rank: rankByFp.get(rawItem.fingerprint),
    target_length: targetLength
  }
}));

const item = $json;

let firstAiredLabel = null;
if (item.first_aired_at) {
  try {
    firstAiredLabel = new Date(item.first_aired_at).toISOString().slice(0, 10);
  } catch (e) {
    firstAiredLabel = null;
  }
}

let systemPrompt;
if (item.is_repeat && item.has_update) {
  systemPrompt = `Summarize this article in approximately ${item.target_length} words for a podcast anchor targeting business leaders. This story has been aired before in this region${firstAiredLabel ? ' (first reported ' + firstAiredLabel + ')' : ''}; the body has been updated since then. Open with "Update on [topic]${firstAiredLabel ? ' (first reported ' + firstAiredLabel + ')' : ''}:" and focus on what is genuinely new. Keep it concise, action-oriented, business-impact focused. Spoken prose, professional tone.`;
} else if (item.is_repeat && !item.has_update) {
  // Safety net — editor should not have selected this. Drop the item so
  // it never reaches Azure OpenAI with a missing payload.
  return [];
} else {
  systemPrompt = `Summarize this article in exactly ${item.target_length} words for a podcast anchor targeting business leaders. Keep it concise, action-oriented, and focus on the business impact. Spoken prose, professional tone.`;
}

const payload = {
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: `Headline: ${item.headline}\n\nContent: ${item.body}` }
  ],
  temperature: 0.7
};
return [{ json: { ...item, llm_payload: payload } }];

const items = $input.all();

// Extract unique source names
const sources = [...new Set(items.map(i => i.json.source_name).filter(Boolean))];

// Format sources list for each language
function formatSources(list, lang) {
  if (list.length === 0) {
    if (lang === 'it') return 'TechCrunch e altre fonti principali';
    if (lang === 'fr') return 'TechCrunch et d\'autres sources majeures';
    if (lang === 'bn') return 'TechCrunch এবং অন্যান্য শীর্ষ সংবাদ মাধ্যম';
    return 'TechCrunch and other top tech outlets';
  }
  if (list.length === 1) return list[0];

  if (lang === 'it') return list.slice(0, -1).join(', ') + ' e ' + list[list.length - 1];
  if (lang === 'fr') return list.slice(0, -1).join(', ') + ' et ' + list[list.length - 1];
  if (lang === 'bn') return list.slice(0, -1).join(', ') + ' এবং ' + list[list.length - 1];
  return list.slice(0, -1).join(', ') + ' and ' + list[list.length - 1];
}

// Get a short headlines preview list (e.g. up to 3 headlines)
const headlines = items.map(i => i.json.headline).filter(Boolean).slice(0, 3);

// Localized summaries/previews of today's topics
const enTopics = headlines.length > 0 ? ' Topics discussed: ' + headlines.join('; ') : '';
const itTopics = headlines.length > 0 ? ' Argomenti trattati: ' + headlines.join('; ') : '';
const frTopics = headlines.length > 0 ? ' Sujets abordés : ' + headlines.join('; ') : '';
const bnTopics = headlines.length > 0 ? ' আলোচিত বিষয়সমূহ: ' + headlines.join('; ') : '';

// Create description for each language
const desc_en = `Welcome to today's English Daily Briefing by NewScriber! Today's stories are curated from ${formatSources(sources, 'en')}. Join your virtual hosts Alex and Sam as they break down the latest updates.${enTopics}`;
const desc_it = `Benvenuti al bollettino quotidiano in italiano di NewScriber! Le storie di oggi sono curate da ${formatSources(sources, 'it')}. Unisciti ai nostri conduttori virtuali Marco e Sofia mentre analizzano le ultime notizie.${itTopics}`;
const desc_fr = `Bienvenue dans le briefing quotidien en français de NewScriber ! Les actualités d'aujourd'hui sont sélectionnées depuis ${formatSources(sources, 'fr')}. Rejoignez vos présentateurs virtuels Pierre et Marie pour décrypter le meilleur de la tech : ${frTopics}`;
const desc_bn = `নিউস্ক্রাইবার বাংলা ডেইলি ব্রিফিংয়ে আপনাদের স্বাগতম! আজকের খবরগুলো নেয়া হয়েছে ${formatSources(sources, 'bn')} থেকে। আমাদের এআই সঞ্চালক ফাহিম এবং নুসরাত আজকের পর্বে আলোচনা করছেন।${bnTopics}`;

return [{
  json: {
    description_en: desc_en,
    description_it: desc_it,
    description_fr: desc_fr,
    description_bn: desc_bn
  }
}];

const items = $('Postgres: Read summaries').all();
const script = items.map(i => i.json.llm_summary).join('\n\n---\n\n');
const targetLang = 'English';
const code = 'en';
const hour = new Date().getHours();
let timeRef = 'today';
if (hour >= 5 && hour < 12) timeRef = 'this morning';
else if (hour >= 12 && hour < 17) timeRef = 'this afternoon';
else if (hour >= 17 && hour < 22) timeRef = 'tonight';
const systemPrompt = `You are a podcast scriptwriter for 'NewScriber'. Assemble these summaries into a 2-person conversation in ${targetLang}. The dialogue MUST be strictly between exactly two speakers: Alex (female host, warm and analytical) and Sam (male host, enthusiastic and tech-savvy). Ensure a gender-balanced conversation with alternating dialogue lines. Start the podcast intro by welcoming the listeners to NewScriber. Use the time reference '${timeRef}' in the intro to anchor the podcast in the present moment. Output the script as a raw JSON array of objects, with each object having 'speaker' and 'text' keys. Do NOT use markdown code blocks.`;
return [{ json: { language: code, summaries: items.length, llm_payload: { messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: script }], temperature: 0.7 } } }];

const reviewNode = $('Review (English)').first().json;
let rawContent = reviewNode.choices[0].message.content || '';
rawContent = rawContent.replace(/^```(?:json)?\n/i, '').replace(/\n```$/i, '').trim();

let englishScript;
try {
  englishScript = JSON.parse(rawContent);
} catch (e) {
  throw new Error(`Failed to parse English script: ${e.message}`);
}

const targetLang = 'Italian';
const code = 'it';
const systemPrompt = `You are a professional translator and script localizer for 'NewScriber'. Your task is to translate and localize the provided English 2-person podcast script into ${targetLang}.

CRITICAL RULES:
1. Keep the exact same dialogue structure, order of stories, turn-taking, and news content. Do not add, omit, or change any of the facts.
2. Translate the dialogue text into natural, spoken, and professional ${targetLang}.
3. Map the speakers exactly as follows:
   - 'Alex' MUST be translated/mapped to 'Sofia' (female host, warm and analytical).
   - 'Sam' MUST be translated/mapped to 'Marco' (male host, enthusiastic and tech-savvy).
4. Output the result as a raw JSON object with a single key 'dialogues' containing an array of objects, with each object having 'speaker' and 'text' keys. Do NOT use markdown code blocks.`;

const userContent = JSON.stringify(englishScript);
return [{ json: { language: code, llm_payload: { messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userContent }], temperature: 0.3 } } }];

